17	template <typename T>
18	constexpr CUtensorMapDataType get_tensor_map_dtype() {
19	  if constexpr (std::is_same_v<T, __half>) {
20	    return CU_TENSOR_MAP_DATA_TYPE_FLOAT16;
21	  } else if constexpr (std::is_same_v<T, __nv_bfloat16>) {
22	    return CU_TENSOR_MAP_DATA_TYPE_BFLOAT16;
23	  } else if constexpr (std::is_same_v<T, float>) {
24	    return CU_TENSOR_MAP_DATA_TYPE_FLOAT32;
25	  } else {
26	    static_assert(std::is_same_v<T, void>, "Unsupported TMA dtype");
27	  }
28	}
