30	inline bool is_experimental_tma_enabled() {
31	  const char* env = std::getenv("ENABLE_FFPA_EXPERIMENTAL_TMA");
32	  return env != nullptr && env[0] != '\0' && env[0] != '0';
33	}
34	
35	inline bool device_supports_tma(int device_index) {
36	  int major = 0;
37	  cudaError_t status = cudaDeviceGetAttribute(
38	      &major, cudaDevAttrComputeCapabilityMajor, device_index);
39	  if (status != cudaSuccess) {
40	    return false;
41	  }
42	  return major >= 9;
43	}
44	
45	inline PFN_cuTensorMapEncodeTiled_v12000 get_cu_tensor_map_encode_tiled() {
46	  cudaDriverEntryPointQueryResult driver_status;
47	  void* entry_point = nullptr;
48	
49	#if CUDA_VERSION >= 12050
50	  cudaGetDriverEntryPointByVersion("cuTensorMapEncodeTiled", &entry_point,
51	                                   12000, cudaEnableDefault, &driver_status);
52	#else
53	  cudaGetDriverEntryPoint("cuTensorMapEncodeTiled", &entry_point,
54	                          cudaEnableDefault, &driver_status);
55	#endif
56	  if (driver_status != cudaDriverEntryPointSuccess || entry_point == nullptr) {
57	    throw std::runtime_error(
58	        "Failed to resolve cuTensorMapEncodeTiled entry point");
59	  }
60	  return reinterpret_cast<PFN_cuTensorMapEncodeTiled_v12000>(entry_point);
61	}
62	
63	template <typename T>
64	struct Copy2DDescriptorParams {
65	  T* global_address;
66	  uint64_t minor_dim;
67	  uint64_t major_dim;
68	  uint64_t major_stride_bytes;
69	  uint32_t box_minor_dim;
70	  uint32_t box_major_dim;
71	  CUtensorMapSwizzle swizzle = CU_TENSOR_MAP_SWIZZLE_NONE;
72	  CUtensorMapL2promotion l2_promotion = CU_TENSOR_MAP_L2_PROMOTION_L2_128B;
73	  CUtensorMapFloatOOBfill oob_fill = CU_TENSOR_MAP_FLOAT_OOB_FILL_NONE;
74	};
75	
76	template <typename T>
77	inline CUtensorMap make_2d_copy_desc(const Copy2DDescriptorParams<T>& params) {
78	  CUtensorMap tensor_map{};
79	  constexpr uint32_t rank = 2;
80	  uint64_t global_dims[rank] = {params.minor_dim, params.major_dim};
81	  uint64_t global_stride[rank - 1] = {params.major_stride_bytes};
82	  uint32_t box_dims[rank] = {params.box_minor_dim, params.box_major_dim};
83	  uint32_t elem_strides[rank] = {1, 1};
84	
85	  auto encode = get_cu_tensor_map_encode_tiled();
86	  CUresult result =
87	      encode(&tensor_map, get_tensor_map_dtype<T>(), rank,
88	             params.global_address, global_dims, global_stride, box_dims,
89	             elem_strides, CU_TENSOR_MAP_INTERLEAVE_NONE, params.swizzle,
90	             params.l2_promotion, params.oob_fill);
91	  if (result != CUDA_SUCCESS) {
92	    throw std::runtime_error(
93	        "cuTensorMapEncodeTiled failed for FFPA experimental TMA descriptor");
94	  }
95	  return tensor_map;
96	}
97	
98	#if defined(__CUDA_ARCH__) && __CUDA_ARCH__ >= 900
99	namespace cde = cuda::device::experimental;
100	
101	__device__ __forceinline__ void init_barrier(barrier_t* barrier,
102	                                             int arrive_count) {
103	  init(barrier, arrive_count);
104	  cde::fence_proxy_async_shared_cta();
105	}
106	
107	__device__ __forceinline__ void wait_barrier(barrier_t& barrier) {
108	  barrier.wait(barrier.arrive());
109	}
110	
111	// Parity-based wait for the direct-write consumers. mbarriers initialised
112	// with ``arrive_count == 1`` and signalled exclusively by the producer's
113	// ``cuda::device::barrier_arrive_tx`` (inside ``load_2d``) flip phase as
114	// soon as the TMA's tx-count is satisfied. Consumers must therefore wait
115	// on the *current* phase bit (0 on the first reuse, 1 on the second,
116	// alternating thereafter) instead of using ``wait(arrive())`` -- the
117	// latter would over-arrive and corrupt the next phase.
118	__device__ __forceinline__ void wait_barrier_parity(barrier_t& barrier,
119	                                                    uint32_t phase) {
120	  barrier.wait_parity(phase != 0);
121	  // The TMA bulk-tensor copy writes via the async proxy; ldmatrix.sync (used
122	  // by the consumer) reads via the generic proxy. mbarrier wait_parity
123	  // alone provides only completion of the TMA, not cross-proxy visibility
124	  // for sm_120 / Blackwell, where a generic-proxy reader must observe an
125	  // explicit ``fence.proxy.async.shared::cta`` after the producer arrival.
126	  cde::fence_proxy_async_shared_cta();
127	}
128	
129	// ------------------------------------------------------------------
130	// TMA bulk-copy commit / wait wrappers
131	// ------------------------------------------------------------------
132	// ``cp.async.bulk.commit_group`` / ``cp.async.bulk.wait_group`` are the
133	// TMA-specific counterparts of the cp.async commit/wait primitives in
134	// ``ffpa::cp_async``. They track ONLY ``cp.async.bulk{,.tensor}`` copies
135	// and are independent of ``cp.async.commit_group`` (the legacy cp.async
136	// group counter does NOT track TMA, and vice versa).
137	//
138	// The SM90 K/V data path uses mbarrier-based completion (every TMA copy in
139	// ``load_2d`` arrives on its per-stage mbarrier via
140	// ``cuda::device::barrier_arrive_tx`` and is awaited in the kernel via
141	// ``wait_barrier_parity``). Mbarrier-tracking is strictly more
142	// expressive than the bulk-group counter (per-slot phases, no FIFO
143	// constraint), so the kernel does not currently call ``bulk_commit_group``
144	// / ``bulk_wait_group``. They are exposed here for two reasons:
145	//
146	//   1. Code-review clarity: it makes the cp.async vs TMA wait split
147	//      explicit. ``ffpa::cp_async::commit_group/wait_group`` only sync Q
148	//      (which is still on cp.async); K/V are synced via
149	//      ``consume_X_tile`` -> ``wait_barrier_parity``.
150	//   2. Future use: a fused bulk_wait_group<0> at the very end of the
151	//      kernel would let us drop the per-slot mbarrier waits if we later
152	//      decide to coarsen the schedule.
153	__device__ __forceinline__ void bulk_commit_group() {
154	  asm volatile("cp.async.bulk.commit_group;\n" ::);
155	}
156	
157	template <size_t n>
158	__device__ __forceinline__ void bulk_wait_group() {
159	  asm volatile("cp.async.bulk.wait_group %0;\n" ::"n"(n));
160	}
161	
162	// Issue a TMA bulk-tensor copy + arrive_tx on the given barrier from
163	// ``issuer_lane`` (default 0). Spreading the issuer across different
164	// lanes / warps splits the per-warp-scheduler LSU dispatch port so that
165	// multiple in-flight issues can be queued in parallel by the hardware
166	// instead of strictly serialising on warp-0 lane-0. The destination
167	// smem and barrier slots are still distinct per call (the kernel rotates
168	// stage / d_tile), so multi-issuer is safe; only the SASS dispatcher
169	// changes.
170	__device__ __forceinline__ void load_2d(void* smem_ptr,
171	                                        const CUtensorMap* tensor_map,
172	                                        int32_t minor_coord,
173	                                        int32_t major_coord, barrier_t& barrier,
174	                                        uint32_t bytes, int issuer_lane = 0) {
175	  if (static_cast<int>(threadIdx.x) == issuer_lane) {
176	    cde::cp_async_bulk_tensor_2d_global_to_shared(
177	        smem_ptr, tensor_map, minor_coord, major_coord, barrier);
178	    [[maybe_unused]] auto token =
179	        cuda::device::barrier_arrive_tx(barrier, 1, bytes);
180	  }
181	}
182	
183	// Issue a TMA bulk-tensor copy directly into the destination swizzled
184	// smem slot. The destination layout is the kernel's existing
185	// ``kPad==0`` XOR-swizzled K/V slot, which (for ``kCols == 16`` fp16,
186	// i.e. 32B per row) is bit-for-bit equivalent to
187	// ``CU_TENSOR_MAP_SWIZZLE_32B`` (Cute ``Swizzle<1, 4, 3>``: address bit
188	// 4 XOR bit 7), and (for ``kCols == 64`` fp16, i.e. 128B per row) is
189	// equivalent to ``CU_TENSOR_MAP_SWIZZLE_128B`` (Cute
190	// ``Swizzle<3, 4, 3>``). The TMA descriptor MUST be configured with
191	// the swizzle mode that matches ``kCols`` so the hardware writes the
192	// same byte pattern that the existing ldmatrix kPad==0 path expects.
193	//
194	// Returns ``false`` and skips the issue when (a) the descriptor is null
195	// or (b) ``d_tile_id`` is past the head-dim end (so speculative prefetch
196	// loops beyond ``kHeadDim/kCols`` are safe to call). KV-axis tail tiles
197	// (``major_coord + BrOrBc > seqlen_bound``) are NOT skipped; the TMA
198	// descriptor's OOB-fill (``CU_TENSOR_MAP_FLOAT_OOB_FILL_NONE``) zero-fills
199	// out-of-bounds rows so no cp.async fallback is needed.
200	//
201	// MUST be paired with ``wait_barrier`` on the same barrier slot before
202	// the destination smem is read.
203	template <const int BrOrBc, const int kHeadDim, const int kCols,
204	          const int kTileSize, typename T>
205	__device__ __forceinline__ bool issue_load_2d_to_dst_swizzled(
206	    T* dst_smem_base_ptr, const CUtensorMap* tensor_map, const int major_coord,
207	    const int d_tile_id, const int dst_stage, barrier_t& barrier,
208	    int issuer_lane = 0) {
209	  if (tensor_map == nullptr || d_tile_id >= (kHeadDim / kCols)) {
210	    return false;
211	  }
212	  T* dst_stage_ptr = dst_smem_base_ptr + dst_stage * kTileSize;
213	  load_2d(dst_stage_ptr, tensor_map, d_tile_id * kCols, major_coord, barrier,
214	          BrOrBc * kCols * sizeof(T), issuer_lane);
215	  return true;
216	}
217	
218	// Legacy scratch+repack issuer: issue an asynchronous TMA load of one
219	// (BrOrBc, kCols) tile into the caller-owned scratch slot ``tmp_stage``
220	// of ``tmp_smem_base_ptr``. Kept for the scratch+repack flow; new code
221	// on SM90+ should prefer ``issue_load_2d_to_dst_swizzled`` above.
222	template <const int BrOrBc, const int kHeadDim, const int kCols, typename T>
223	__device__ __forceinline__ bool issue_load_2d_to_tmp(
224	    T* tmp_smem_base_ptr, const CUtensorMap* tensor_map, const int major_coord,
225	    const int d_tile_id, const int tmp_stage, const int seqlen_bound,
226	    barrier_t& barrier) {
227	  if (tensor_map == nullptr || d_tile_id >= (kHeadDim / kCols) ||
228	      ((major_coord + BrOrBc) > seqlen_bound)) {
229	    return false;
230	  }
231	  T* tmp_stage_ptr = tmp_smem_base_ptr + tmp_stage * BrOrBc * kCols;
232	  load_2d(tmp_stage_ptr, tensor_map, d_tile_id * kCols, major_coord, barrier,
233	          BrOrBc * kCols * sizeof(T));
234	  return true;
235	}
236	
237	// Wait on ``barrier`` (signalled by the matching ``issue_load_2d_to_tmp``
238	// call with the same ``tmp_stage``) and repack the contiguous TMA scratch
239	// tile at ``tmp_smem_base_ptr[tmp_stage]`` into the kernel's existing
240	// padded (kPad>0) or XOR-swizzled (kPad==0) destination slot
241	// ``dst_smem_base_ptr[dst_stage]``. All threads in the block participate.
242	//
243	// MUST only be invoked when the matching ``issue_load_2d_to_tmp`` returned
244	// ``true``; otherwise the wait will block forever (no producer arrival).
245	template <const int BrOrBc, const int kTileSize, const int kCols,
246	          const int kNumThreads, const int kPad, typename T>
247	__device__ __forceinline__ void wait_and_repack_tmp_to_dst(T* dst_smem_base_ptr,
248	                                                           T* tmp_smem_base_ptr,
249	                                                           const int dst_stage,
250	                                                           const int tmp_stage,
251	                                                           barrier_t& barrier) {
252	  constexpr bool kSwizzle = (kPad == 0);
253	  constexpr int kElemsPerThread = kCols / (kNumThreads / BrOrBc);
254	  static_assert(kElemsPerThread * sizeof(T) == 16,
255	                "Experimental TMA repack expects one 16B vector per thread.");
256	
257	  T* tmp_stage_ptr = tmp_smem_base_ptr + tmp_stage * BrOrBc * kCols;
258	  wait_barrier(barrier);
259	  __syncthreads();
260	
261	  const int tid = threadIdx.x;
262	  const int row = tid / (kNumThreads / BrOrBc);
263	  const int col = (tid % (kNumThreads / BrOrBc)) * kElemsPerThread;
264	  T* src = tmp_stage_ptr + row * kCols + col;
265	  T* dst = dst_smem_base_ptr + dst_stage * kTileSize + row * (kCols + kPad) +
266	           (kSwizzle ? (((col >> 3) ^ (row >> 2)) % (kCols >> 3)) << 3 : col);
267	  *reinterpret_cast<uint4*>(dst) = *reinterpret_cast<uint4*>(src);
268	  __syncthreads();
269	}
270	
271	// Legacy synchronous helper kept for completeness: issues, waits and
272	// repacks in a single call. Equivalent to ``issue_load_2d_to_tmp`` +
273	// ``wait_and_repack_tmp_to_dst`` back-to-back. New code should prefer
274	// the split helpers so that the issue and the wait can be hoisted apart
275	// to enable multi-stage TMA pipelining.
276	template <const int BrOrBc, const int kTileSize, const int kHeadDim,
277	          const int kCols, const int kNumThreads, const int kPad, typename T>
278	__device__ __forceinline__ bool load_2d_to_smem_repack(
279	    T* dst_smem_base_ptr, T* tmp_smem_base_ptr, const CUtensorMap* tensor_map,
280	    const int major_coord, const int d_tile_id, const int dst_stage,
281	    const int tmp_stage, const int seqlen_bound, barrier_t& barrier) {
282	  if (!issue_load_2d_to_tmp<BrOrBc, kHeadDim, kCols, T>(
283	          tmp_smem_base_ptr, tensor_map, major_coord, d_tile_id, tmp_stage,
284	          seqlen_bound, barrier)) {
285	    return false;
286	  }
287	  wait_and_repack_tmp_to_dst<BrOrBc, kTileSize, kCols, kNumThreads, kPad, T>(
288	      dst_smem_base_ptr, tmp_smem_base_ptr, dst_stage, tmp_stage, barrier);
289	  return true;
290	}
291	#else
292	__device__ __forceinline__ void init_barrier(barrier_t* barrier,
293	                                             int arrive_count) {
294	  (void)barrier;
295	  (void)arrive_count;
296	}
297	
298	__device__ __forceinline__ void wait_barrier(barrier_t& barrier) {
299	  (void)barrier;
300	}
301	
302	__device__ __forceinline__ void wait_barrier_parity(barrier_t& barrier,
303	                                                    uint32_t phase) {
304	  (void)barrier;
305	  (void)phase;
306	}
307	
308	__device__ __forceinline__ void bulk_commit_group() {}
309	
310	template <size_t n>
311	__device__ __forceinline__ void bulk_wait_group() {}
312	
313	__device__ __forceinline__ void load_2d(void* smem_ptr,
314	                                        const CUtensorMap* tensor_map,
315	                                        int32_t minor_coord,
316	                                        int32_t major_coord, barrier_t& barrier,
317	                                        uint32_t bytes, int issuer_lane = 0) {
318	  (void)smem_ptr;
319	  (void)tensor_map;
320	  (void)minor_coord;
321	  (void)major_coord;
322	  (void)barrier;
323	  (void)bytes;
324	  (void)issuer_lane;
325	}
