        const int tile_V_d = (j >> 1);  // (j / 2)
        const int smem_sel_v = (tile_V_d) % kStagePV;
        const int smem_sel_v_next = (tile_V_d + (kStagePV - 1)) % kStagePV;
        // V g2s, V tile smem [Bc,kMmaAtomN*2]=[64,16]
