    float* lane_row_sum_new,        // &lane_row_sum_new[0][0]
    float* lane_block_row_max_old,  // &lane_block_row_max_old[0][0]
    float* lane_block_row_sum_old   // &lane_block_row_sum_old[0][0]
) {
