        // (x,y) 0~7->{c0, c1}, (z,w)->8~15 {c2, c3}
        float* t_fptr_S_0_1 = reinterpret_cast<float*>(R_S + j * 4);
        kDataType* t_hptr_S_0_1 = reinterpret_cast<kDataType*>(R_S + j * 4);
