      lane_row_max_new[0] = warp::reduce_max<float, 4>(lane_row_max_new[0]);
      lane_row_max_new[1] = warp::reduce_max<float, 4>(lane_row_max_new[1]);
    }  // end for kValTileSeqLenQ

    // static_assert(kValTileSeqLenQ == 1);
