// ``sync_store_o_r2g`` can emit 128-bit global stores.
template <const int kValTileHeadDimV, const int kOStorageAccFloat32,
          typename kDataType = __half>
__device__ __forceinline__ void sync_rescaling_final_o(
    uint32_t* R_D,                       // Final O after loop over N
    const float* lane_block_row_sum_old  // &lane_block_row_sum_old[0][0]
) {
  using Traits = DtypeTraits<kDataType>;
  // Finaly, we still have to rescale O once more.
  // O_output(D) = ( 1/l_final ) * O_final (FA2 paper)
  // static_assert(kValTileSeqLenP == 1);
  {  // kValTileSeqLenP = 1
    const float rescale_factor_0 = __frcp_rn(lane_block_row_sum_old[0]);
    const float rescale_factor_1 = __frcp_rn(lane_block_row_sum_old[1]);
#pragma unroll
    for (int j = 0; j < kValTileHeadDimV; ++j) {  // 8, 16, 32, ...
      // Scaling in registers & convert F32 -> kDataType for O collective store.
      if constexpr (kOStorageAccFloat32) {
        const float* t_fptr_D_0_1 = reinterpret_cast<float*>(R_D + j * 4);
        kDataType* t_hptr_D_0_1 = reinterpret_cast<kDataType*>(R_D + j * 4);
        t_hptr_D_0_1[0] =
            Traits::from_float(rescale_factor_0 * t_fptr_D_0_1[0]);
        t_hptr_D_0_1[1] =
            Traits::from_float(rescale_factor_0 * t_fptr_D_0_1[1]);
        t_hptr_D_0_1[2] =
            Traits::from_float(rescale_factor_1 * t_fptr_D_0_1[2]);
        t_hptr_D_0_1[3] =
            Traits::from_float(rescale_factor_1 * t_fptr_D_0_1[3]);
      } else {
        kDataType* t_hptr_D_0_1 = reinterpret_cast<kDataType*>(R_D + j * 2);
        t_hptr_D_0_1[0] = Traits::from_float(rescale_factor_0 *
                                             Traits::to_float(t_hptr_D_0_1[0]));
        t_hptr_D_0_1[1] = Traits::from_float(rescale_factor_0 *
                                             Traits::to_float(t_hptr_D_0_1[1]));
        t_hptr_D_0_1[2] = Traits::from_float(rescale_factor_1 *
                                             Traits::to_float(t_hptr_D_0_1[2]));
        t_hptr_D_0_1[3] = Traits::from_float(rescale_factor_1 *
                                             Traits::to_float(t_hptr_D_0_1[3]));
      }
    }  // end for kValTileHeadDimV
  }  // end for kValTileSeqLenP = 1
}

// Collective write-back of the softmax LSE values from registers to gmem.
// Each 4-thread subgroup within a warp writes the logsumexp for the two Q
// rows it owns: ``lse = log(row_sum) + row_max``.  Thread 0 of each group
// emits both values via plain 32-bit global stores so the write pattern
// matches the O-store row order exactly.
template <const int Br, const int kMmaAtomM, const int kValTileSeqLenQ>
__device__ __forceinline__ void sync_store_lse_r2g(
    float* __restrict__ gmem_lse_ptr, const int gmem_lse_offset,
    const int n_tile_id, const int mma_tile_id,
    const float* lane_block_row_max_old, const float* lane_block_row_sum_old,
    const int seqlen_bound = INT_MAX) {
  // LSE = log(row_sum) + row_max (row_sum = sum_i exp(S_i - row_max))
  const float lse_0 =
      __logf(lane_block_row_sum_old[0]) + lane_block_row_max_old[0];
  const float lse_1 =
      __logf(lane_block_row_sum_old[1]) + lane_block_row_max_old[1];

  const int lane_id = threadIdx.x % WARP_SIZE;
  // Thread 0 of each 4-thread subgroup writes both rows; row indices mirror
  // sync_store_o_r2g's layout so that LSE[i] corresponds to O[i,:].
  if (lane_id % 4 == 0) {
    const int row_in_warp = lane_id / 4;  // 0..7
    const int global_row_0 =
        n_tile_id * Br + mma_tile_id * kMmaAtomM + row_in_warp;
    const int global_row_1 =
        n_tile_id * Br + mma_tile_id * kMmaAtomM + row_in_warp + 8;
    const int lse_idx_0 = gmem_lse_offset + global_row_0;
    const int lse_idx_1 = gmem_lse_offset + global_row_1;
    if (global_row_0 < seqlen_bound) {
      gmem_lse_ptr[lse_idx_0] = lse_0;
    }
    if (global_row_1 < seqlen_bound) {
      gmem_lse_ptr[lse_idx_1] = lse_1;
    }
  }
}

// Collective write-back of the final O tile from registers to gmem.
// Uses warp-shuffles across lane_id % 4 to pack the per-thread fragment
// layout into contiguous 128-bit vectors, then ``st.global.v4`` once per
// (lane % 4 == 0) thread. Scratch registers ``R_Q`` / ``R_K`` are reused
// as the shuffle staging buffers so no extra SMEM is needed. Rows with
// global idx >= ``seqlen_bound`` are not written, keeping tail padding
// (N % Br != 0) untouched.
template <const int Br, const int kHeadDim, const int kMmaAtomM,
          const int kMmaAtomN, const int kValTileHeadDimV,
          const int kOStorageAccFloat32, typename kDataType = __half>
__device__ __forceinline__ void sync_store_o_r2g(
    kDataType* gmem_ptr,              // O gmem ptr
    const int gmem_offset,            // O gmem global offset
    const int n_tile_id,              // curr tile id (seqlen) O_tile_id
    const int mma_tile_id,            // Q warp_QP 0~num MMAs, KV warp_KV 0
    uint32_t* R_D,                    // Final scaled O
    uint32_t* R_Q,                    // R_Q[1][4] for registers reuse
    uint32_t* R_K,                    // R_K[8][2] for registers reuse
    const int seqlen_bound = INT_MAX  // per-row bound: rows with global idx >=
                                      // seqlen_bound are not written to gmem
) {
  // Store O(D): Write O[Br,d] from regs -> gmem, collective store
  // with reg reuse & warp shuffle.
  const int lane_id = threadIdx.x % WARP_SIZE;  // 0~31
  // static_assert(kValTileSeqLenP == 1);
  {  // kValTileSeqLenP = 1
#pragma unroll
    for (int j = 0; j < kValTileHeadDimV; ++j) {  // 8
      // reuse R_Q[1][4], R_K[8][2] for collective store.
      uint32_t* t_uptr_Z_0 = reinterpret_cast<uint32_t*>(R_Q);
      uint32_t* t_uptr_Z_1 = reinterpret_cast<uint32_t*>(R_K);
      const int offset = (kOStorageAccFloat32) ? j * 4 : j * 2;
      t_uptr_Z_0[0] = R_D[offset + 0];
      t_uptr_Z_1[0] = R_D[offset + 1];
      t_uptr_Z_0[1] =
          __shfl_sync((0xffffffff), R_D[offset + 0], lane_id + 1, 4);
      t_uptr_Z_0[2] =
          __shfl_sync((0xffffffff), R_D[offset + 0], lane_id + 2, 4);
      t_uptr_Z_0[3] =
          __shfl_sync((0xffffffff), R_D[offset + 0], lane_id + 3, 4);

// ============================================================================
// ffpa_attn_persistent_d_fwd_template
// ----------------------------------------------------------------------------
// Split-Q (FlashAttention-2) prefill attention kernel tuned for *small* head
// dimensions (D <= 128, up to 256). Unlike the "large-d" variant, this kernel
// persists the full Q / K / V tile across head-dim within one KV step (no
// inner tile_K_d loop), matching the classical FA-2 schedule. It therefore
// uses more SMEM but fewer synchronizations, giving better throughput when D
// is small.
//
// Supports cross-attention, GQA/MQA, and runtime causal attention with the
// same semantics as the large-d template; see that header for the full
// contract.
//
// ----------------------------------------------------------------------------
// Template parameters (compile-time configuration)
// ----------------------------------------------------------------------------
//   kDataType            Activation dtype: __half or __nv_bfloat16.
//   kHeadDim             Head dimension D; must satisfy D <= 256
//   (static_assert). kMmaAtomM/N/K        MMA atom shape for m16n8k16 (fixed to
//   16/8/16). kMmaTileSeqLenQ/K/P  Warp-level MMA tiling along Q rows / K cols
//   / P rows. kMmaTileHeadDimV     Warp-level MMA tiling along V cols
//   (head-dim). kValTileSeqLenQ/K/P  Value-level multipliers forming Br, Bc as
//   in the
//                        large-d template.
//   kValTileHeadDimV     Value tiling over head-dim for P@V.
//   kMmaAccFloat32QK/PV  0 -> fp16 MMA accumulator, 1 -> fp32 accumulator
//                        (bf16 requires 1).
//   kOStorageAccFloat32  0/1, O accumulator storage dtype selector.
//   kPrefetchQK/PV       0/1, enable async prefetch of next QK / PV tiles.
//   kShareSmemQKV        0/1, share QK SMEM region when kPersistQs2r is on.
//   kPersistQs2r         0/1, persist Q registers across all KV tiles.
//   kPersistVs2r         0/1, persist the full V tile in registers across the
//                        P@V inner loop (only viable for small D).
//   kRegPipeKV           0/1, register ping-pong between ldmatrix and mma.
//                        Mutually exclusive with kPersistVs2r.
//   kStageQK/kStagePV    Must both be 1 for this template (static_assert).
//   kPadQ/kPadK/kPadV    0 -> SMEM swizzle, >0 -> padded SMEM layout.
//
// ----------------------------------------------------------------------------
// Runtime parameters
// ----------------------------------------------------------------------------
//   Q   in : fp16/bf16 tensor, shape [Nb, Nh, Nq,  D].
//   K   in : fp16/bf16 tensor, shape [Nb, Nh_kv, Nkv, D].
//   V   in : fp16/bf16 tensor, shape [Nb, Nh_kv, Nkv, D].
//   O   out: fp16/bf16 tensor, shape [Nb, Nh, Nq,  D]; written in place.
//   Nb     : Batch size; combined with Nh to fan out across gridDim.y.
//   Nq     : Query sequence length; drives gridDim.x = div_ceil(Nq, Br) and
//            the tail-row store predicate.
//   Nkv    : Key/Value sequence length (Nk == Nv); drives the KV loop bound
//            Tc = div_ceil(Nkv, Bc) and the tail-tile softmax mask.
//   Nh     : Number of Q attention heads (Nh_q); combined with blockIdx.y
//            to recover (batch, head) indices.
//   Nh_kv  : Number of K/V heads (GQA/MQA). Must divide Nh.
//   scale  : Softmax pre-scale, typically 1 / sqrt(D).
