    launch_ffpa_attn_fwd_template<__half, 512, kMmaAccFloat32QK, kMmaAccFloat32PV, 1>(Q, K, V, O, attn_bias, softmax_lse, causal, softmax_scale, dropout_p, philox_seed, philox_offset, tma);
  }
#else
