290	// current CUDA stream. Validates Q/K/V/O shape invariants up-front via
291	// ``TORCH_CHECK`` (GQA/MQA head ratio, matching Nkv / D, and the
292	// ``causal => Nkv >= Nq`` rule).
293	//
294	// Template parameters:
295	//   kDataType            Activation dtype: ``__half`` or ``__nv_bfloat16``.
296	//   kHeadDim             Head dim D (32, 64, ..., 1024); selects the
297	//                        small-d vs large-d kernel and the block tile.
298	//   kMmaAccFloat32QK/PV  0 -> fp16 MMA accumulator, 1 -> fp32 accumulator.
299	//                        Must both be 1 for bf16 activations.
300	//   kStage               cp.async pipeline depth used for QK (the PV
301	//                        depth is derived inside the launcher).
302	//
303	// Runtime arguments:
304	//   Q, K, V, O     : BHND tensors as described in the kernel template docs.
305	//   causal         : 0/1 runtime flag. Non-zero enables causal masking with
306	//                    queries aligned to the KV tail; requires Nkv >= Nq.
307	//   softmax_scale  : pre-softmax scaling factor applied to QK^T. Matches the
308	//                    flash-attn naming; the Python wrapper defaults it to
309	//                    ``1 / sqrt(D)`` when the caller does not supply one.
310	// Runtime ``tma`` is accepted for API compatibility but ignored. The legacy
311	// SM90 TMA CUDA branch is kept under csrc/cuffpa/deprecated; active native
312	// forward launches always use the architecture-agnostic templates here.
313	template <typename kDataType, const int kHeadDim, const int kMmaAccFloat32QK,
314	          const int kMmaAccFloat32PV, const int kStage>
315	void launch_ffpa_attn_fwd_template(torch::Tensor Q, torch::Tensor K,
316	                                   torch::Tensor V, torch::Tensor O,
317	                                   torch::Tensor attn_bias,
318	                                   torch::Tensor softmax_lse, int causal,
319	                                   double softmax_scale, double dropout_p,
320	                                   int64_t philox_seed, int64_t philox_offset,
321	                                   int tma) {
322	  (void)tma;
323	  // Q,K,V,O with [B, H, N, D] layout, B=batch, H=head, N=seqlen, D=dim
324	  // TODO: support BNHD layout, Q,K,V,O with [B, N, H, D] layout.
325	  constexpr int kMmaAtomM = 16;
326	  constexpr int kMmaAtomN = 8;
327	  constexpr int kMmaAtomK = 16;
328	  // Split-Q(FA-2) Algo, Tile MMA across Q and keep KV access for all MMAs.
329	  constexpr int kMmaTileSeqLenQ = getConfigMmaTileSeqLenQP<kHeadDim>();
330	  constexpr int kMmaTileSeqLenK = 1;
331	  constexpr int kMmaTileSeqLenP = getConfigMmaTileSeqLenQP<kHeadDim>();
332	  constexpr int kMmaTileHeadDimV = 1;
333	  constexpr int kValTileSeqLenQ = 1;
334	  constexpr int kValTileSeqLenK = getConfigWarpTileSeqLenK<kHeadDim>();
335	  constexpr int kValTileSeqLenP = 1;
336	  constexpr int kValTileHeadDimV = getConfigWarpTileHeadDimV<kHeadDim>();
337	  constexpr int Br = kMmaAtomM * kMmaTileSeqLenQ * kValTileSeqLenQ;
338	  constexpr int Bc = kMmaAtomN * kMmaTileSeqLenK * kValTileSeqLenK;
339	  static_assert(Br == Bc,
340	                "Br must be equal Bc to avoid illegal memory access.");
341	  constexpr int kNumThreads = WARP_SIZE * kMmaTileSeqLenQ * kMmaTileSeqLenK;
342	  constexpr int kOStorageAccFloat32 = getConfigOStorageAccFloat32<kHeadDim>();
343	  // Apply different multi stages policy for QK and V.
344	  // TODO: tune stages for Q@K and P@V.
345	  constexpr int kStageQK = kStage;  // <= 4
346	  constexpr int kStagePV = kStage;  // <= 4
347	  // Prefetch QKV, Persist Q g2s/s2r, Shared QKV smem.
348	  constexpr int kShareSmemQKV = getConfigShareSmemQKV();
349	  constexpr int kPrefetchQK = getConfigPrefetchQKV<kStageQK>();
350	  constexpr int kPrefetchPV = getConfigPrefetchQKV<kStagePV>();
351	  constexpr int kPersistQs2r = getConfigPersistQs2r();
352	  constexpr int kPersistQg2s = getConfigPersistQg2s<kStageQK, kHeadDim>();
353	  constexpr int kRegPipeKV = getConfigRegistersPipeKV();
354	  // QKV smem swizzle, 0 for smem swizzle, !0 for smem padding.
355	  constexpr int kPadQ = getConfigPadQ();
356	  constexpr int kPadK = getConfigPadK();
357	  constexpr int kPadV = getConfigPadV();
358	  // Calculate SRAM size needed for per block.
359	  constexpr int kQKVSmemMaxSize =
360	      getConfigQKVSmemMaxSize<Br, Bc, kMmaAtomM, kMmaAtomN, kMmaAtomK, kHeadDim,
361	                              kShareSmemQKV, kPersistQg2s, kPersistQs2r,
362	                              kStageQK, kStagePV, kPadQ, kPadK, kPadV>();
363	  TORCH_CHECK(K.size(0) == Q.size(0) && V.size(0) == Q.size(0),
364	              "ffpa_attn: Q/K/V must share the same batch size");
365	  TORCH_CHECK(K.size(1) == V.size(1),
366	              "ffpa_attn: K and V must share the same num_heads (Nh_kv)");
367	  TORCH_CHECK(
368	      Q.size(1) % K.size(1) == 0,
369	      "ffpa_attn: Q num_heads must be an integer multiple of K/V num_heads "
370	      "(GQA/MQA group_size = Nh_q / Nh_kv)");
371	  TORCH_CHECK(K.size(2) == V.size(2),
372	              "ffpa_attn: K and V must have identical sequence length (Nkv)");
373	  TORCH_CHECK(K.size(3) == Q.size(3) && V.size(3) == Q.size(3),
374	              "ffpa_attn: Q/K/V must share the same head dim");
375	  TORCH_CHECK(causal == 0 || K.size(2) >= Q.size(2),
376	              "ffpa_attn: causal attention requires Nkv >= Nq (queries are "
377	              "aligned to the tail of the KV sequence)");
378	  const int Nb = Q.size(0);
379	  const int Nh = Q.size(1);  // Q head count (Nh_q); used for grid fan-out.
380	  const int Nh_kv =
381	      K.size(1);  // K/V head count; Nh % Nh_kv == 0 asserted above.
382	  // Cross-attention: Q seqlen (Nq) may differ from KV seqlen (Nkv).
383	  const int Nq = Q.size(2);
384	  const int Nkv = K.size(2);
385	  const bool has_attn_bias = attn_bias.numel() != 0;
386	  const bool has_dropout = dropout_p > 0.0;
387	  TORCH_CHECK(causal == 0 || !has_attn_bias,
388	              "ffpa_attn: explicit attn_mask should not be set when causal "
389	              "attention is enabled");
390	  const void* attn_bias_ptr = nullptr;
391	  int attn_bias_dtype = 0;
392	  long long attn_bias_stride_b = 0;
393	  long long attn_bias_stride_h = 0;
394	  long long attn_bias_stride_m = 0;
395	  long long attn_bias_stride_n = 0;
396	  if (has_attn_bias) {
397	    TORCH_CHECK(attn_bias.is_cuda(),
398	                "ffpa_attn: attn_mask must be a CUDA tensor");
399	    TORCH_CHECK(attn_bias.device() == Q.device(),
400	                "ffpa_attn: attn_mask must be on the same device as Q/K/V");
401	    TORCH_CHECK(
402	        attn_bias.dim() == 4,
403	        "ffpa_attn: normalized attn_mask must be 4-D [B, Nh_q, Nq, Nkv]");
404	    TORCH_CHECK(attn_bias.size(0) == 1 || attn_bias.size(0) == Nb,
405	                "ffpa_attn: attn_mask batch dimension must be 1 or B");
406	    TORCH_CHECK(attn_bias.size(1) == 1 || attn_bias.size(1) == Nh,
407	                "ffpa_attn: attn_mask head dimension must be 1 or Nh_q");
408	    TORCH_CHECK(attn_bias.size(2) == 1 || attn_bias.size(2) == Nq,
409	                "ffpa_attn: attn_mask query dimension must be 1 or Nq");
410	    TORCH_CHECK(attn_bias.size(3) == 1 || attn_bias.size(3) == Nkv,
411	                "ffpa_attn: attn_mask key dimension must be 1 or Nkv");
412	    TORCH_CHECK(attn_bias.stride(3) == 1,
413	                "ffpa_attn: normalized attn_mask must be contiguous along the "
414	                "key dimension");
415	    const auto bias_type = attn_bias.scalar_type();
416	    if (bias_type == torch::kHalf) {
417	      attn_bias_dtype = 1;
418	    } else if (bias_type == torch::kBFloat16) {
419	      attn_bias_dtype = 2;
420	    } else if (bias_type == torch::kFloat32) {
421	      attn_bias_dtype = 3;
422	    } else {
423	      TORCH_CHECK(false,
424	                  "ffpa_attn: attn_mask dtype must be fp16, bf16, or fp32");
425	    }
426	    TORCH_CHECK(bias_type == torch::kFloat32 || bias_type == Q.scalar_type(),
427	                "ffpa_attn: attn_mask dtype must be fp32 or match Q dtype");
428	    attn_bias_ptr = attn_bias.data_ptr();
429	    attn_bias_stride_b =
430	        (attn_bias.size(0) == 1 && Nb > 1) ? 0 : attn_bias.stride(0);
431	    attn_bias_stride_h =
432	        (attn_bias.size(1) == 1 && Nh > 1) ? 0 : attn_bias.stride(1);
433	    attn_bias_stride_m =
434	        (attn_bias.size(2) == 1 && Nq > 1) ? 0 : attn_bias.stride(2);
435	    attn_bias_stride_n =
436	        (attn_bias.size(3) == 1 && Nkv > 1) ? 0 : attn_bias.stride(3);
437	  }
438	  // Seqlen (Nq, Nkv) no longer has to be a multiple of max(Br, Bc): the
439	  // kernel handles the tail tile via cp.async zero-fill, softmax -inf
440	  // masking and a per-row store predicate. div_ceil(Nkv, Bc) below still
441	  // yields the right Tc for partial last KV tiles.
442	
443	  const dim3 block = getConfigBlock<kNumThreads>();  // 4/8 warps per block
444	  // grid is driven by Q row tiles; KV tile count Tc is driven by Nkv.
445	  const dim3 grid = getConfigGrid<Br>(Nb, Nh, Nq);
446	  const int Tc = utils::div_ceil(Nkv, Bc);  // Tc K_tile[Bc,d]
447	  const float scale = static_cast<float>(softmax_scale);
448	  const float dropout_p_f = static_cast<float>(dropout_p);
449	  const unsigned long long philox_seed_u =
450	      static_cast<unsigned long long>(philox_seed);
451	  const unsigned long long philox_offset_u =
452	      static_cast<unsigned long long>(philox_offset);
453	  float* softmax_lse_ptr = softmax_lse.data_ptr<float>();
454	
455	  // Launch on the caller's current CUDA stream so the kernel participates
456	  // correctly in multi-stream pipelines. Without this the kernel would
457	  // default to stream 0 and race against user-side non-default streams.
458	  const c10::cuda::OptionalCUDAGuard device_guard(Q.device());
459	  auto stream = at::cuda::getCurrentCUDAStream();
460	
461	  if constexpr (kHeadDim > kMaxDForSmallDKernel) {
462	    const int num_sms_x2 =
463	        max(1, at::cuda::getCurrentDeviceProperties()->multiProcessorCount * 2);
464	    const int num_splits = select_decode_num_splits(
465	        Nb * Nh * utils::div_ceil(Nq, 16), num_sms_x2, Tc, 128, min(Nq, 16));
466	    if (Nq == 1 && num_splits > 1 && !has_attn_bias && !has_dropout) {
467	      const int split_size = utils::div_ceil(Tc, num_splits) * Bc;
468	      auto scratch_options =
469	          torch::TensorOptions().dtype(torch::kFloat32).device(Q.device());
470	      auto partial_out =
471	          torch::empty({Nb, Nh, num_splits, Nq, kHeadDim}, scratch_options);
472	      auto chunk_lse = torch::empty({Nb, Nh, num_splits, Nq}, scratch_options);
473	      const dim3 decode_stage1_grid = dim3(num_splits, Nb * Nh, 1);
474	      const dim3 decode_stage2_grid = dim3(Nq, Nb * Nh, 1);
475	      const int decode_threads =
476	          ((kHeadDim / 8) + WARP_SIZE - 1) / WARP_SIZE * WARP_SIZE;
477	      const dim3 decode_block = dim3(decode_threads, 1, 1);
478	      // Pure gemv implementation for Nq=1 case, do the reduction in stage 2.
479	      auto decode_stage1_kernel =
